using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents and raw SQL
            // (SELECT * FROM c WHERE c.Discriminator = 'Blog') keep working.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: Id no longer includes discriminator prefix.
            // EF Core 9 maps the key directly to JSON "id"; old docs use "Blog|1" format.
            // Keep the CLR key mapped to JSON "Id" and restore the shadow id property.
            b.Property(e => e.Id).ToJsonProperty("Id");
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: HasIndex now throws for Cosmos (was silently ignored).
            // Removed: b.HasIndex(b => b.Name);
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

/// <summary>
/// Restores the EF Core 8 Cosmos id format: "{Discriminator}|{Key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var entityType = entry.Metadata;
        var discriminator = entityType.GetDiscriminatorValue()?.ToString()
            ?? entityType.ShortName();
        var key = entry.Property(entityType.FindPrimaryKey()!.Properties[0]).CurrentValue;
        return $"{discriminator}|{key}";
    }
}

